#include <stdio.h>
#include <signal.h>
#include <unistd.h>

void sigint_handler(int signum) {
 printf("\nReceived SIGINT (Ctrl+C)! Cleaning up...\n");
 /* Perform cleanup operations */
 /* Exit gracefully */
 _exit(0);
}

int main() {
 /* Set up signal handler for SIGINT */
 signal(SIGINT, sigint_handler);

 printf("Process running. Press Ctrl+C to terminate.\n");

 /* Infinite loop */
 while(1) {
 sleep(1);
 printf("Still running...\n");
 }

 return 0;
}

#include <stdio.h>
#include <signal.h>
#include <unistd.h>

/* Signal handler function */
void handle_signal(int signum) {
 printf("\nCaught signal %d\n", signum);
}

int main() {
 struct sigaction sa;

 /* Initialize the structure */
 sa.sa_handler = handle_signal;
 sigemptyset(&sa.sa_mask);

 /* Add signals to block during handler execution */
 sigaddset(&sa.sa_mask, SIGTERM);

 /* Set flags: restart system calls interrupted by this signal */
 sa.sa_flags = SA_RESTART;

 /* Set up signal handler for SIGINT */
 if (sigaction(SIGINT, &sa, NULL) == -1) {
 perror("sigaction");
 return 1;
 }

 printf("Process running. Press Ctrl+C.\n");

 /* Example of system call that would be restarted */
 while(1) {
 sleep(5); /* This will be restarted if interrupted */
 }

 return 0;
}

#include <stdio.h>
#include <signal.h>
#include <unistd.h>

void handler(int signum) {
 printf("Handler caught signal %d\n", signum);
}

int main() {
 sigset_t block_mask, old_mask, pending_mask;
 struct sigaction sa;

 /* Set up handler */
 sa.sa_handler = handler;
 sigemptyset(&sa.sa_mask);
 sa.sa_flags = 0;
 sigaction(SIGUSR1, &sa, NULL);

 /* Initialize signal sets */
 sigemptyset(&block_mask);
 sigaddset(&block_mask, SIGUSR1);

 /* Block SIGUSR1 */
 if (sigprocmask(SIG_BLOCK, &block_mask, &old_mask) == -1) {
 perror("sigprocmask");
 return 1;
 }

 printf("SIGUSR1 is now blocked.\n");
 printf("Sending SIGUSR1 to self...\n");
 raise(SIGUSR1); /* Generate signal - will be pending */

 /* Check for pending signals */
 sigpending(&pending_mask);
 if (sigismember(&pending_mask, SIGUSR1)) {
 printf("SIGUSR1 is pending (blocked).\n");
 }

 /* Unblock SIGUSR1 - handler will be called */
 printf("Unblocking SIGUSR1...\n");
 if (sigprocmask(SIG_SETMASK, &old_mask, NULL) == -1) {
 perror("sigprocmask");
 return 1;
 }

 printf("Main function completed.\n");
 return 0;
}
